report_script:
salary_slip = frappe.qb.DocType("Salary Slip")
salary_detail = frappe.qb.DocType("Salary Detail")
salary_component = frappe.qb.DocType("Salary Component")
employee_doctype = frappe.qb.DocType("Employee")


def execute(filters=None):
	if not filters:
		filters = {}

	currency = None
	if filters.get("currency"):
		currency = filters.get("currency")
	company_currency = frappe.db.get_value("Company", filters.get("company"), "default_currency")

	salary_slips = get_salary_slips(filters, company_currency)
	if not salary_slips:
		return [], []

	earning_types, ded_types = get_earning_and_deduction_types(salary_slips)
	columns = get_columns(earning_types, ded_types)

	ss_earning_map = get_salary_slip_details(salary_slips, currency, company_currency, "earnings")
	ss_ded_map = get_salary_slip_details(salary_slips, currency, company_currency, "deductions")

	emp_map = get_employee_extra_map()

	data = []
	for ss in salary_slips:
		emp_info = emp_map.get(ss.employee) or {}
		total_days = frappe.utils.date_diff(ss.end_date, ss.start_date) + 1

		row = {
			"salary_slip_id": ss.name,
			"employee": ss.employee,
			"employee_name": ss.employee_name,
			"data_of_joining": emp_info.get("date_of_joining"),
			"left": 1 if emp_info.get("relieving_date") else 0,
			"status": emp_info.get("status"),
			"branch": ss.branch,
			"department": ss.department,
			"designation": ss.designation,
			"company": ss.company,
			"start_date": ss.start_date,
			"end_date": ss.end_date,
			"days_in_month": total_days,
			"leave_without_pay": ss.leave_without_pay,
			"absent_days": ss.absent_days,
			"payment_days": ss.payment_days,
			"currency": currency or company_currency,
			"total_loan_repayment": ss.total_loan_repayment,
		}

		update_column_width(ss, columns)

		for e in earning_types:
			row[frappe.scrub(e)] = ss_earning_map.get(ss.name, {}).get(e)

		for d in ded_types:
			row[frappe.scrub(d)] = ss_ded_map.get(ss.name, {}).get(d)

		if currency == company_currency:
			row["gross_pay"] = frappe.utils.flt(ss.gross_pay) * frappe.utils.flt(ss.exchange_rate)
			row["total_deduction"] = (frappe.utils.flt(ss.total_deduction) + frappe.utils.flt(ss.total_loan_repayment)) * frappe.utils.flt(ss.exchange_rate)
			row["net_pay"] = frappe.utils.flt(ss.net_pay) * frappe.utils.flt(ss.exchange_rate)
		else:
			row["gross_pay"] = ss.gross_pay
			row["total_deduction"] = frappe.utils.flt(ss.total_deduction) + frappe.utils.flt(ss.total_loan_repayment)
			row["net_pay"] = ss.net_pay

		data.append(row)

	return columns, data


def get_earning_and_deduction_types(salary_slips):
	earnings = []
	deductions = []

	for sc in get_salary_components(salary_slips):
		component_type = get_salary_component_type(sc)
		if component_type == "Earning":
			earnings.append(sc)
		elif component_type == "Deduction":
			deductions.append(sc)

	return sorted(earnings), sorted(deductions)


def update_column_width(ss, columns):
	if ss.branch is not None:
		columns[6]["width"] = 120
	if ss.department is not None:
		columns[7]["width"] = 120
	if ss.designation is not None:
		columns[8]["width"] = 120
	if ss.leave_without_pay is not None:
		columns[13]["width"] = 120


def get_columns(earning_types, ded_types):
	columns = [
		{"label": "Salary Slip ID", "fieldname": "salary_slip_id", "fieldtype": "Link", "options": "Salary Slip", "width": 150},
		{"label": "Employee", "fieldname": "employee", "fieldtype": "Link", "options": "Employee", "width": 120},
		{"label": "Employee Name", "fieldname": "employee_name", "fieldtype": "Data", "width": 140},
		{"label": "Date of Joining", "fieldname": "data_of_joining", "fieldtype": "Date", "width": 80},
		{"label": "Left?", "fieldname": "left", "fieldtype": "Check", "width": 60},
		{"label": "Status", "fieldname": "status", "fieldtype": "Data", "width": 90},
		{"label": "Branch", "fieldname": "branch", "fieldtype": "Link", "options": "Branch", "width": -1},
		{"label": "Department", "fieldname": "department", "fieldtype": "Link", "options": "Department", "width": -1},
		{"label": "Designation", "fieldname": "designation", "fieldtype": "Link", "options": "Designation", "width": 120},
		{"label": "Company", "fieldname": "company", "fieldtype": "Link", "options": "Company", "width": 120},
		{"label": "Start Date", "fieldname": "start_date", "fieldtype": "Data", "width": 80},
		{"label": "End Date", "fieldname": "end_date", "fieldtype": "Data", "width": 80},
		{"label": "Days In Month", "fieldname": "days_in_month", "fieldtype": "Float", "width": 100},
		{"label": "Leave Without Pay", "fieldname": "leave_without_pay", "fieldtype": "Float", "width": 50},
		{"label": "Absent Days", "fieldname": "absent_days", "fieldtype": "Float", "width": 50},
		{"label": "Payment Days", "fieldname": "payment_days", "fieldtype": "Float", "width": 120},
	]

	for earning in earning_types:
		columns.append({"label": earning, "fieldname": frappe.scrub(earning), "fieldtype": "Currency", "options": "currency", "width": 120})

	columns.append({"label": "Gross Pay", "fieldname": "gross_pay", "fieldtype": "Currency", "options": "currency", "width": 120})

	for deduction in ded_types:
		columns.append({"label": deduction, "fieldname": frappe.scrub(deduction), "fieldtype": "Currency", "options": "currency", "width": 120})

	if "lending" in frappe.get_installed_apps():
		columns.append({"label": "Loan Repayment", "fieldname": "total_loan_repayment", "fieldtype": "Currency", "options": "currency", "width": 120})

	columns.append({"label": "Total Deduction", "fieldname": "total_deduction", "fieldtype": "Currency", "options": "currency", "width": 120})
	columns.append({"label": "Net Pay", "fieldname": "net_pay", "fieldtype": "Currency", "options": "currency", "width": 120})
	columns.append({"label": "Currency", "fieldname": "currency", "fieldtype": "Data", "options": "Currency", "hidden": 1})

	return columns


def get_salary_components(salary_slips):
	return (
		frappe.qb.from_(salary_detail)
		.where((salary_detail.amount != 0) & (salary_detail.parent.isin([d.name for d in salary_slips])))
		.select(salary_detail.salary_component)
		.distinct()
	).run(pluck=True)


def get_salary_component_type(component_name):
	return frappe.db.get_value("Salary Component", component_name, "type", cache=True)


def get_salary_slips(filters, company_currency):
	doc_status = {"Draft": 0, "Submitted": 1, "Cancelled": 2}

	query = frappe.qb.from_(salary_slip).select(salary_slip.star)

	if filters.get("docstatus"):
		query = query.where(salary_slip.docstatus == doc_status[filters.get("docstatus")])
	if filters.get("from_date"):
		query = query.where(salary_slip.start_date >= filters.get("from_date"))
	if filters.get("to_date"):
		query = query.where(salary_slip.end_date <= filters.get("to_date"))
	if filters.get("company"):
		query = query.where(salary_slip.company == filters.get("company"))
	if filters.get("employee"):
		query = query.where(salary_slip.employee == filters.get("employee"))
	if filters.get("currency") and filters.get("currency") != company_currency:
		query = query.where(salary_slip.currency == filters.get("currency"))
	if filters.get("department"):
		query = query.where(salary_slip.department == filters["department"])
	if filters.get("designation"):
		query = query.where(salary_slip.designation == filters["designation"])
	if filters.get("branch"):
		query = query.where(salary_slip.branch == filters["branch"])

	return query.run(as_dict=1) or []


def get_employee_extra_map():
	result = (
		frappe.qb.from_(employee_doctype)
		.select(employee_doctype.name, employee_doctype.date_of_joining, employee_doctype.status, employee_doctype.relieving_date)
	).run(as_dict=1)

	emp_map = {}
	for r in result:
		emp_map[r.name] = r
	return emp_map


def get_salary_slip_details(salary_slips, currency, company_currency, component_type):
	slip_names = [ss.name for ss in salary_slips]

	result = (
		frappe.qb.from_(salary_slip)
		.join(salary_detail)
		.on(salary_slip.name == salary_detail.parent)
		.where((salary_detail.parent.isin(slip_names)) & (salary_detail.parentfield == component_type))
		.select(salary_detail.parent, salary_detail.salary_component, salary_detail.amount, salary_slip.exchange_rate)
	).run(as_dict=1)

	ss_map = {}
	for d in result:
		if d.parent not in ss_map:
			ss_map[d.parent] = {}
		if d.salary_component not in ss_map[d.parent]:
			ss_map[d.parent][d.salary_component] = 0.0

		if currency == company_currency:
			existing = ss_map[d.parent][d.salary_component]
			ss_map[d.parent][d.salary_component] = existing + frappe.utils.flt(d.amount) * frappe.utils.flt(d.exchange_rate or 1)
		else:
			existing = ss_map[d.parent][d.salary_component]
			ss_map[d.parent][d.salary_component] = existing + frappe.utils.flt(d.amount)

	return ss_map
